import { Card, FileUpload } from '@moduix/react';
import styles from './file-upload-manager.module.css';

const maxFiles = 5;
const maxFileSize = 10 * 1024 * 1024;

function FileUploadManager() {
  return (
    <div className={styles.surface}>
      <FileUpload
        className={styles.fileUpload}
        accept="application/pdf,.doc,.docx,image/png,image/jpeg"
        maxFiles={maxFiles}
        maxFileSize={maxFileSize}
      >
        <Card className={styles.card}>
          <Card.Header>
            <div>
              <FileUpload.Label className={styles.title}>Project attachments</FileUpload.Label>
              <Card.Description>
                Share briefs, documents, and reference images with your team.
              </Card.Description>
            </div>
            <FileUpload.Context>
              {({ acceptedFiles }) =>
                acceptedFiles.length ? (
                  <Card.Action>
                    <FileUpload.ClearTrigger className={styles.clearTrigger}>
                      Clear all
                    </FileUpload.ClearTrigger>
                  </Card.Action>
                ) : null
              }
            </FileUpload.Context>
          </Card.Header>

          <Card.Body className={styles.body}>
            <FileUpload.Dropzone className={styles.dropzone} disableClick>
              <FileUpload.DropzoneIcon className={styles.dropzoneIcon} />
              <div className={styles.dropzoneContent}>
                <strong>Drop files here</strong>
                <span>PDF, DOCX, PNG, or JPG up to 10 MB</span>
              </div>
              <FileUpload.Trigger className={styles.trigger}>Browse files</FileUpload.Trigger>
            </FileUpload.Dropzone>

            <FileUpload.Context>
              {({ acceptedFiles, rejectedFiles }) => (
                <div className={styles.fileList}>
                  <div className={styles.listHeader}>
                    <span>Attachments</span>
                    <span className={styles.fileCount} aria-live="polite">
                      {acceptedFiles.length} of {maxFiles} files
                    </span>
                  </div>

                  {acceptedFiles.length ? (
                    <FileUpload.ItemGroup className={styles.items}>
                      <FileUpload.Items />
                    </FileUpload.ItemGroup>
                  ) : (
                    <p className={styles.emptyState}>No files added yet.</p>
                  )}

                  {rejectedFiles.length ? (
                    <FileUpload.ItemGroup className={styles.rejectedItems} type="rejected">
                      {rejectedFiles.map(({ file, errors }) => (
                        <FileUpload.Item key={`${file.name}-${file.lastModified}`} file={file}>
                          <FileUpload.ItemName />
                          <p className={styles.error} role="alert">
                            {errors.join(', ')}
                          </p>
                          <FileUpload.ItemDeleteTrigger aria-label={`Remove ${file.name}`} />
                        </FileUpload.Item>
                      ))}
                    </FileUpload.ItemGroup>
                  ) : null}
                </div>
              )}
            </FileUpload.Context>
          </Card.Body>
        </Card>
      </FileUpload>
    </div>
  );
}

export { FileUploadManager };

.surface {
  display: grid;
  width: 100%;
  min-width: 0;
  padding: clamp(var(--moduix-spacing-4), 5vw, var(--moduix-spacing-8));
}

.fileUpload {
  --moduix-file-upload-max-width: min(100%, 42rem);

  width: 100%;
  min-width: 0;
  max-width: 100%;
}

.card {
  width: 100%;
  min-width: 0;
}

.body {
  display: grid;
  gap: var(--moduix-spacing-6);
  min-width: 0;
}

.listHeader {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--moduix-spacing-4);
}

.title {
  color: var(--moduix-color-foreground);
  font-size: var(--moduix-text-lg);
  font-weight: var(--moduix-weight-semibold);
  line-height: var(--moduix-line-height-text-lg);
}

.fileCount,
.dropzoneContent span {
  color: var(--moduix-color-muted-foreground);
  font-size: var(--moduix-text-sm);
  line-height: var(--moduix-line-height-text-sm);
}

.clearTrigger {
  flex: none;
}

.dropzone {
  display: grid;
  min-height: 12rem;
  place-items: center;
  align-content: center;
  gap: var(--moduix-spacing-3);
  padding: var(--moduix-spacing-6);
  border: var(--moduix-border-width-sm) dashed
    color-mix(in oklab, var(--moduix-color-border) 82%, var(--moduix-color-foreground));
  border-radius: var(--moduix-radius-lg);
  background: color-mix(in oklab, var(--moduix-color-muted) 45%, transparent);
  text-align: center;
  transition: var(--moduix-transition-default);

  &[data-dragging] {
    border-color: var(--moduix-color-primary);
    background: color-mix(in oklab, var(--moduix-color-primary) 8%, var(--moduix-color-background));
  }
}

.dropzoneIcon {
  color: var(--moduix-color-primary);
}

.dropzoneContent {
  display: grid;
  gap: var(--moduix-spacing-1);
}

.dropzoneContent strong,
.listHeader > span:first-child {
  color: var(--moduix-color-foreground);
  font-size: var(--moduix-text-sm);
  font-weight: var(--moduix-weight-semibold);
  line-height: var(--moduix-line-height-text-sm);
}

.trigger {
  margin-block-start: var(--moduix-spacing-1);
}

.items,
.rejectedItems {
  min-width: 0;
  gap: var(--moduix-spacing-2);
}

.fileList {
  display: grid;
  gap: var(--moduix-spacing-3);
  min-width: 0;
  padding-block-start: var(--moduix-spacing-4);
  border-block-start: var(--moduix-border-width-sm) solid var(--moduix-color-border);
}

.items [data-slot='file-upload-item'],
.rejectedItems [data-slot='file-upload-item'] {
  min-width: 0;
  max-width: 100%;
}

.emptyState {
  margin: 0;
  color: var(--moduix-color-muted-foreground);
  font-size: var(--moduix-text-sm);
  line-height: var(--moduix-line-height-text-sm);
}

.rejectedItems [data-slot='file-upload-item'] {
  border-color: color-mix(
    in oklab,
    var(--moduix-color-destructive) 36%,
    var(--moduix-color-border)
  );
}

.error {
  grid-column: 2;
  margin: 0;
  color: var(--moduix-color-destructive);
  font-size: var(--moduix-text-xs);
  line-height: var(--moduix-line-height-text-xs);
}

@media (width < 34rem) {
  .surface {
    padding: var(--moduix-spacing-3);
  }

  .listHeader {
    align-items: flex-start;
  }

  .dropzone {
    min-height: 10rem;
    padding: var(--moduix-spacing-5);
  }
}
